import React, { useState } from "react";
import "./styles/App.css";
import BillingScreen from "./components/BillingScreen";
import RecentBills from "./components/RecentBills";
import FoodMenu from "./components/FoodMenu";
import AdminDashboard from "./components/AdminDashboard";
import ShiftManagement from "./components/ShiftManagement";

const Button = ({ children, onClick, className = "" }) => (
  <button onClick={onClick} className={`px-3 py-2 rounded ${className}`}>
    {children}
  </button>
);

function LoginPanel({ onLogin }) {
  const [credential, setCredential] = useState("");
  const [date, setDate] = useState(new Date().toISOString().split("T")[0]);
  const submit = () => onLogin(credential || "clerk", date);
  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50">
      <div className="w-full max-w-md bg-white p-6 rounded shadow">
        <h2 className="text-lg font-semibold mb-4">Staff Login</h2>
        <div className="space-y-3">
          <input
            placeholder="Credential"
            className="w-full border px-2 py-1"
            value={credential}
            onChange={(e) => setCredential(e.target.value)}
          />
          <input
            type="date"
            className="w-full border px-2 py-1"
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />
          <button
            className="w-full bg-blue-600 text-white px-3 py-2 rounded"
            onClick={submit}
          >
            Login
          </button>
        </div>
      </div>
    </div>
  );
}

function AdminPanel({ mode, onLogout }) {
  if (!mode || !mode.includes("admin")) return null;
  return (
    <div className="space-y-4">
      <div className="bg-white shadow rounded p-4">
        <h3 className="font-semibold">Admin Dashboard</h3>
        <AdminDashboard />
      </div>
      <div className="bg-white shadow rounded p-4">
        <h3 className="font-semibold">Shift Management</h3>
        <ShiftManagement mode={mode} onLogout={onLogout} />
      </div>
    </div>
  );
}

export default function App() {
  const [mode, setMode] = useState("none");
  const [billingDate, setBillingDate] = useState(null);
  const [activeTab, setActiveTab] = useState("billing");
  const handleLogin = (newMode, date) => {
    setMode(newMode || "clerk");
    setBillingDate(date);
  };
  const handleLogout = () => {
    setMode("none");
    setBillingDate(null);
    setActiveTab("billing");
  };
  if (mode === "none") return <LoginPanel onLogin={handleLogin} />;
  const isAdmin = mode && mode.includes("admin");
  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white shadow-sm border-b py-4">
        <div className="max-w-6xl mx-auto px-4 flex justify-between items-center">
          <h1 className="text-xl font-bold">Restaurant Billing</h1>
          <div className="text-sm">
            Mode: {mode} | Date: {billingDate}
          </div>
        </div>
      </header>
      <main className="max-w-6xl mx-auto p-4">
        <nav className="flex gap-2 mb-4">
          <Button
            onClick={() => setActiveTab("billing")}
            className={
              activeTab === "billing" ? "bg-blue-600 text-white" : "bg-white"
            }
          >
            Billing
          </Button>
          <Button
            onClick={() => setActiveTab("menu")}
            className={
              activeTab === "menu" ? "bg-blue-600 text-white" : "bg-white"
            }
          >
            Food Menu
          </Button>
          <Button
            onClick={() => setActiveTab("bills")}
            className={
              activeTab === "bills" ? "bg-blue-600 text-white" : "bg-white"
            }
          >
            Recent Bills
          </Button>
          {isAdmin && (
            <Button
              onClick={() => setActiveTab("admin")}
              className={
                activeTab === "admin" ? "bg-blue-600 text-white" : "bg-white"
              }
            >
              Admin
            </Button>
          )}
          <div className="ml-auto">
            <Button onClick={handleLogout} className="bg-red-500 text-white">
              Logout
            </Button>
          </div>
        </nav>
        {activeTab === "billing" && <BillingScreen />}
        {activeTab === "menu" && <FoodMenu />}
        {activeTab === "bills" && <RecentBills billingDate={billingDate} />}
        {activeTab === "admin" && (
          <AdminPanel mode={mode} onLogout={handleLogout} />
        )}
      </main>
    </div>
  );
}
